import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/axiosConfig';
import { LayoutDashboard, History, PlusCircle, ArrowUpRight, ShieldCheck } from 'lucide-react';

const DashboardPage = () => {
  const [strategies, setStrategies] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchVaultData = async () => {
      try {
        const res = await api.get('/portfolio/history');
        setStrategies(res.data);
      } catch (err) {
        console.error('VAULT_SYNC_ERROR', err);
      } finally {
        setLoading(false);
      }
    };
    fetchVaultData();
  }, []);

  /* ── Loading State ── */
  if (loading) return (
    <div style={{
      flex: 1,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '1rem',
      minHeight: '60vh',
    }}>
      <div style={{
        width: '120px', height: '2px',
        background: 'var(--surface-border)',
        borderRadius: '999px',
        overflow: 'hidden',
      }}>
        <div style={{
          height: '100%',
          width: '40%',
          background: 'var(--accent-primary)',
          borderRadius: '999px',
          animation: 'slideLoader 1.4s ease-in-out infinite',
        }} />
      </div>
      <p style={{
        fontSize: '0.6rem',
        color: 'var(--accent-primary)',
        textTransform: 'uppercase',
        letterSpacing: '0.35em',
        margin: 0,
      }}>
        decrypting_vault...
      </p>
      <style>{`
        @keyframes slideLoader {
          0%   { transform: translateX(-100%); }
          100% { transform: translateX(350%); }
        }
      `}</style>
    </div>
  );

  return (
    <div
      className="reveal-node"
      style={{
        flex: 1,
        width: '100%',
        maxWidth: '960px',
        margin: '0 auto',
        padding: '2.5rem 1.5rem',
        boxSizing: 'border-box',
      }}
    >
      {/* ── Header ── */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'flex-end',
        marginBottom: '2.5rem',
        paddingBottom: '1.5rem',
        borderBottom: '1px solid var(--surface-border)',
      }}>
        <div>
          <h1 style={{
            display: 'flex',
            alignItems: 'center',
            gap: '0.75rem',
            fontSize: '1.6rem',
            fontWeight: 800,
            letterSpacing: '-0.03em',
            textTransform: 'uppercase',
            color: 'var(--text-primary)',
            margin: '0 0 0.5rem',
          }}>
            <LayoutDashboard size={24} color="var(--accent-primary)" />
            Terminal_<span style={{ color: 'var(--accent-primary)' }}>Dashboard</span>
          </h1>
          <p style={{
            fontSize: '0.58rem',
            color: 'var(--text-muted)',
            textTransform: 'uppercase',
            letterSpacing: '0.28em',
            margin: 0,
          }}>
            Secure Node Active // Location: Pune, IN
          </p>
        </div>

        {/* System health badge */}
        <div style={{ textAlign: 'right' }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'flex-end',
            gap: '0.4rem',
            fontSize: '0.58rem',
            fontWeight: 700,
            textTransform: 'uppercase',
            letterSpacing: '0.15em',
            color: 'var(--text-muted)',
            marginBottom: '0.3rem',
          }}>
            <ShieldCheck size={11} color="var(--accent-primary)" />
            System_Health
          </div>
          <p style={{
            fontSize: '1.1rem',
            fontWeight: 800,
            letterSpacing: '0.2em',
            color: 'var(--accent-primary)',
            margin: 0,
            textShadow: '0 0 12px var(--accent-glow)',
          }}>
            OPTIMAL
          </p>
        </div>
      </div>

      {/* ── Strategy Grid ── */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
        gap: '1rem',
      }}>
        {strategies.map((item) => (
          <StrategyCard
            key={item.id}
            item={item}
            onClick={() => navigate(`/portfolio/${item.id}`)}
          />
        ))}

        {/* ── New Strategy CTA ── */}
        <button
          onClick={() => navigate('/generate')}
          style={{
            gridColumn: strategies.length === 0 ? '1 / -1' : undefined,
            padding: strategies.length === 0 ? '4rem 2rem' : '2rem',
            background: 'transparent',
            border: '2px dashed var(--surface-border)',
            borderRadius: '20px',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            gap: '0.75rem',
            cursor: 'pointer',
            transition: 'all 0.3s ease',
            color: 'var(--text-muted)',
          }}
          onMouseEnter={e => {
            e.currentTarget.style.borderColor = 'var(--accent-primary)';
            e.currentTarget.style.background  = 'var(--accent-muted)';
          }}
          onMouseLeave={e => {
            e.currentTarget.style.borderColor = 'var(--surface-border)';
            e.currentTarget.style.background  = 'transparent';
          }}
        >
          <div style={{
            width: '52px', height: '52px',
            borderRadius: '50%',
            background: 'var(--surface-border)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            transition: 'background 0.3s ease',
          }}>
            <PlusCircle size={26} color="var(--accent-primary)" />
          </div>
          {strategies.length === 0 && (
            <p style={{
              fontSize: '0.6rem',
              textTransform: 'uppercase',
              letterSpacing: '0.2em',
              color: 'var(--text-muted)',
              margin: 0,
            }}>
              Vault_Is_Empty: No_Strategies_Generated
            </p>
          )}
          <span style={{
            fontSize: '0.65rem',
            fontWeight: 700,
            textTransform: 'uppercase',
            letterSpacing: '0.18em',
            color: 'var(--accent-primary)',
          }}>
            Initialize_Strategy_Engine →
          </span>
        </button>
      </div>
    </div>
  );
};

/* ── Strategy Card sub-component ── */
const StrategyCard = ({ item, onClick }) => {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        position: 'relative',
        padding: '1.5rem',
        borderRadius: '18px',
        background: 'var(--surface-glass)',
        border: `1px solid ${hovered ? 'var(--accent-primary)' : 'var(--surface-border)'}`,
        boxShadow: hovered ? '0 0 24px var(--accent-glow)' : 'var(--shadow-elevated)',
        cursor: 'pointer',
        overflow: 'hidden',
        transition: 'all 0.3s ease',
        backdropFilter: 'blur(12px)',
        WebkitBackdropFilter: 'blur(12px)',
      }}
    >
      {/* Top row */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.25rem' }}>
        <div style={{
          width: '38px', height: '38px',
          borderRadius: '10px',
          background: 'var(--accent-muted)',
          border: '1px solid var(--accent-primary)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}>
          <History size={16} color="var(--accent-primary)" />
        </div>
        <ArrowUpRight
          size={16}
          color={hovered ? 'var(--accent-primary)' : 'var(--text-muted)'}
          style={{ transition: 'color 0.25s ease' }}
        />
      </div>

      {/* Title */}
      <h3 style={{
        fontSize: '0.95rem',
        fontWeight: 700,
        color: hovered ? 'var(--accent-primary)' : 'var(--text-primary)',
        margin: '0 0 1.25rem',
        transition: 'color 0.25s ease',
        overflow: 'hidden',
        textOverflow: 'ellipsis',
        whiteSpace: 'nowrap',
      }}>
        {item.goal || 'Unnamed Strategy'}
      </h3>

      {/* Footer */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        paddingTop: '0.875rem',
        borderTop: '1px solid var(--surface-border)',
      }}>
        <span style={{
          fontSize: '0.58rem',
          color: 'var(--text-muted)',
          textTransform: 'uppercase',
          letterSpacing: '0.18em',
        }}>
          {new Date(item.created_at).toLocaleDateString()}
        </span>
        <span style={{
          fontSize: '0.58rem',
          fontWeight: 700,
          color: 'var(--accent-primary)',
          textTransform: 'uppercase',
          letterSpacing: '0.15em',
          opacity: hovered ? 1 : 0,
          transition: 'opacity 0.25s ease',
        }}>
          VIEW_DETAILS
        </span>
      </div>

      {/* Hover glow strip at bottom */}
      {hovered && (
        <div style={{
          position: 'absolute',
          bottom: 0, left: 0, right: 0,
          height: '2px',
          background: 'linear-gradient(90deg, transparent, var(--accent-primary), transparent)',
        }} />
      )}
    </div>
  );
};

export default DashboardPage;
